import{_ as r,c as a,o,a1 as s}from"./chunks/framework.DDNAyvCW.js";const g=JSON.parse('{"title":"隐私设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/privacy/settings/index.md","filePath":"docs/privacy/settings/index.md"}'),e={name:"docs/privacy/settings/index.md"};function d(n,t,i,l,p,c){return o(),a("div",null,t[0]||(t[0]=[s('<h1 id="隐私设置" tabindex="-1">隐私设置 <a class="header-anchor" href="#隐私设置" aria-label="Permalink to &quot;隐私设置&quot;">​</a></h1><p>控制 Chaterm 收集哪些数据、如何处理敏感信息以及是否跨设备同步你的设置。</p><p>有关具体跟踪内容和原因的详细信息，请参阅<a href="/docs/privacy/policy/">隐私政策</a>。</p><h2 id="遥测" tabindex="-1">遥测 <a class="header-anchor" href="#遥测" aria-label="Permalink to &quot;遥测&quot;">​</a></h2><p>遥测功能发送匿名使用数据和错误报告，帮助改进 Chaterm。不会收集任何代码、提示词或对话内容。</p><table tabindex="0"><thead><tr><th>数据类别</th><th>包含内容</th></tr></thead><tbody><tr><td>任务交互</td><td>任务的开始/结束时间、对话流程（不含内容）</td></tr><tr><td>模式与工具使用</td><td>所选的 AI 模式、调用的工具</td></tr><tr><td>令牌使用量</td><td>用于成本估算的对话长度指标</td></tr><tr><td>用户界面活动</td><td>各界面功能的使用情况</td></tr><tr><td>错误报告</td><td>匿名化的错误信息</td></tr></tbody></table><p><strong>开关</strong>：设置 &gt; 隐私 &gt; 遥测 -- <strong>开启</strong>或<strong>关闭</strong>。</p><div class="tip custom-block"><p class="custom-block-title">建议</p><p>开启遥测功能可以帮助 Chaterm 团队优先处理功能需求和更快修复问题。所有数据都经过匿名化处理，不会泄露隐私信息。</p></div><h2 id="密文脱敏" tabindex="-1">密文脱敏 <a class="header-anchor" href="#密文脱敏" aria-label="Permalink to &quot;密文脱敏&quot;">​</a></h2><p>密文脱敏功能可在 AI 对话框输出中自动遮盖密码、密钥、令牌和其他敏感信息。</p><p><strong>功能说明</strong>：</p><ul><li>实时识别常见的敏感信息模式</li><li>在内容显示在屏幕上之前进行遮盖</li><li>不影响正常使用</li></ul><p><strong>使用场景</strong>：</p><ul><li>共享屏幕或录制会话时</li><li>在公共环境中工作时</li><li>审查可能包含凭证的 AI 输出时</li></ul><p><strong>开关</strong>：设置 &gt; 隐私 &gt; 密文脱敏 -- <strong>开启</strong>或<strong>关闭</strong>。</p><div class="warning custom-block"><p class="custom-block-title">限制</p><p>脱敏功能可以覆盖常见的敏感信息模式，但无法保证 100% 检测。在处理高度敏感的信息时，请务必谨慎。</p></div><h2 id="数据同步" tabindex="-1">数据同步 <a class="header-anchor" href="#数据同步" aria-label="Permalink to &quot;数据同步&quot;">​</a></h2><p>数据同步功能使你的配置、资产和密钥在所有使用 Chaterm 的设备上保持一致。</p><p><strong>同步的数据</strong>：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>示例</th></tr></thead><tbody><tr><td>资产</td><td>主机连接详情、SSH 密钥</td></tr><tr><td>凭证</td><td>保存的密码和令牌</td></tr><tr><td>AI 历史对话</td><td>历史 AI 对话记录</td></tr></tbody></table><p>所有同步数据在传输和存储过程中均使用 KMS 加密。</p><p><strong>开关</strong>：设置 &gt; 隐私 &gt; 数据同步 -- <strong>开启</strong>或<strong>关闭</strong>。</p><div class="warning custom-block"><p class="custom-block-title">云端存储</p><p>开启数据同步后，你的配置数据会存储在云端。在敏感环境中启用此功能前，请确保你信任 Chaterm 的安全措施。</p></div><div class="tip custom-block"><p class="custom-block-title">建议</p><p>如果你在多台设备上使用 Chaterm，开启数据同步可以避免重复配置，提供一致的使用体验。</p></div><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><p><strong>数据最小化</strong> -- 仅启用需要的功能，定期检查隐私设置。</p><p><strong>敏感信息</strong> -- 在演示或录制时保持脱敏功能开启。避免在对话中直接粘贴敏感信息，建议使用环境变量或密钥管理器。</p><p><strong>多设备使用</strong> -- 在共享或公共设备上使用 Chaterm 后，及时清理本地数据。定期检查已同步的数据内容。</p>',28)]))}const m=r(e,[["render",d]]);export{g as __pageData,m as default};
